import (
	"sort"
)

func solve(nums []int64, k int64) int64 {
	sort.Slice(nums, func(i, j int) bool { return nums[i] < nums[j] })
	n := int64(len(nums))
	minRemove := n - 1 // worst case: keep only one element

	for i := int64(0); i < n; i++ {
		minVal := nums[i]
		maxVal := minVal * k
		j := sort.Search(len(nums), func(idx int) bool { return nums[idx] > maxVal })
		keep := int64(j) - i
		if n-keep < minRemove {
			minRemove = n - keep
		}
	}

	return minRemove
}
